def predict_v4(features: dict) -> int:
    score = 0.5
    # 基础校准：无高危条件时 score<0.5，降低假阳性
    score -= 0.15
    # Respiratory_failure：强阳性关联，但部分 FP 中该特征单独出现，适当降低权重
    if features.get('Respiratory_failure', 0) == 1:
        score += 0.20
    # sepsis：脓毒症核心指标，保持权重
    if features.get('sepsis', 0) == 1:
        score += 0.15
    # age>65：高龄风险，权重不变
    if features.get('age', 60) > 65:
        score += 0.05
    # SOFA>6：高死亡率，降权后保持以控制 FP
    if features.get('SOFA', 0) > 6:
        score += 0.05
    # mbp<65：休克指标
    if features.get('mbp', 80) < 65:
        score += 0.1
    # ICH：颅内血肿，高风险
    if features.get('ICH', 0) == 1:
        score += 0.15
    # Cerebral_infarction：脑梗死，降权后保持
    if features.get('Cerebral_infarction', 0) == 1:
        score += 0.05
    # wbc 极端值：感染/炎症
    wbc = features.get('wbc', 10)
    if wbc < 4 or wbc > 12:
        score += 0.05
    # Urea_Nitrogen>28：肾功能不全，上调权重以捕获更多 FN
    if features.get('Urea_Nitrogen', 20) > 28:
        score += 0.05
    # 年龄<40：年轻，降低假阳性
    if features.get('age', 60) < 40:
        score -= 0.05
    return 1 if score >= 0.5 else 0
